{
  "decisions": [
    {
      "id": "D1",
      "content": "役員会承認を受け、プロジェクト・アオゾラを2026-05-13付で正式にキックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00から1時間で開催し、各部署から最低1名が参加する運用とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "第1フェーズのデータ移行はマスタ系のみを対象とし、トランザクション履歴は旧システムを参照用に残す方針で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信の共通基盤は、サクラ商事との共同利用案で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行テストと負荷テストは、システムテストとは別立てで計画・実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "ユーザー権限は既存のロール定義を流用し、ロール定義の再設計は稼働後の運用改善として切り分ける。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "障害発生時の一次受け窓口はQAチームが担当する運用にする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "移行方式は、拠点をグループ分けして順次切り替える段階移行とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "本番リリースの目標日は2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "各グループの切替作業は土曜深夜に実施し、日曜を予備日に充てる前提で進める。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "議事録を作成し、会議参加者全員へ共有する。",
      "assignee": "桐生 遥",
      "due": "2026-05-13"
    },
    {
      "id": "A2",
      "task": "検証環境用サーバの調達依頼を提出する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "開発ベンダー見積の社内稟議を起票する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A4",
      "task": "現場ヒアリング対象部署と窓口候補者のリストを提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A5",
      "task": "外部連携API仕様書のドラフトを作成する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A6",
      "task": "サクラ商事への共同利用回答書を作成して送付する。",
      "assignee": "桐生 遥",
      "due": "2026-05-22"
    },
    {
      "id": "A7",
      "task": "負荷試験用の専用実行環境を構築する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-25"
    },
    {
      "id": "A8",
      "task": "現場向け説明会の日程案を各拠点分調整して提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A9",
      "task": "既存テストケースを棚卸しし、存廃区分付きの一覧を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-29"
    },
    {
      "id": "A10",
      "task": "外部ライセンス費用の再見積を取得する。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A11",
      "task": "移行テスト計画を作成する。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A12",
      "task": "負荷テスト計画を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A13",
      "task": "移行リハーサルの手順書を作成する。",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    }
  ],
  "key_numbers": [
    {
      "id": "N1",
      "label": "現行在庫管理システムの稼働年数",
      "value": "11年"
