      "value": "1.2秒以内"
    },
    {
      "id": "N6",
      "label": "移行対象トランザクション件数",
      "value": "1200万件"
    },
    {
      "id": "N7",
      "label": "移行対象マスタ件数",
      "value": "約48万件"
    },
    {
      "id": "N8",
      "label": "検証環境の想定サーバ台数",
      "value": "9台"
    },
    {
      "id": "N9",
      "label": "今期システム予算枠（前回500万円の1.2倍として算出）",
      "value": "600万円"
    },
    {
      "id": "N10",
      "label": "開発用外部ライセンス費用の試算（4.5万円/人月×8人×3か月）",
      "value": "108万円"
    }
  ]
}

